import React, { useState, useEffect } from 'react';
import { useAuth } from '../../context/AuthContext';
import { orderService } from '../../services/orderService';
import './Orders.css';

const STATUS_CONFIG = {
  PLACED: { color: '#f59e0b', bg: '#fef3c7', icon: '📦' },
  PROCESSING: { color: '#3b82f6', bg: '#dbeafe', icon: '⚙️' },
  SHIPPED: { color: '#8b5cf6', bg: '#ede9fe', icon: '🚚' },
  DELIVERED: { color: '#10b981', bg: '#d1fae5', icon: '✅' },
  CANCELLED: { color: '#ef4444', bg: '#fee2e2', icon: '❌' },
};

const Orders = () => {
  const { user } = useAuth();
  const [orders, setOrders] = useState([]);
  const [loading, setLoading] = useState(true);
  const [expanded, setExpanded] = useState(null);

  useEffect(() => {
    loadOrders();
  }, []);

  const loadOrders = async () => {
    try {
      const data = await orderService.getOrdersByUserId(user.userId || user.user_id);
      setOrders(data || []);
    } catch {
      setOrders([]);
    } finally {
      setLoading(false);
    }
  };

  if (loading) return (
    <div className="orders-page">
      <div className="orders-header"><h1>My Orders</h1></div>
      <div className="orders-loading">
        {[1,2,3].map(i => <div key={i} className="order-skeleton"></div>)}
      </div>
    </div>
  );

  return (
    <div className="orders-page">
      <div className="orders-header">
        <h1>My Orders</h1>
        <p>{orders.length} order{orders.length !== 1 ? 's' : ''} placed</p>
      </div>

      {orders.length === 0 ? (
        <div className="orders-empty">
          <div className="orders-empty-icon">📦</div>
          <h2>No orders yet</h2>
          <p>Your order history will appear here</p>
        </div>
      ) : (
        <div className="orders-list">
          {orders.map((order) => {
            const status = order.orderStatus || order.order_status || 'PLACED';
            const cfg = STATUS_CONFIG[status] || STATUS_CONFIG.PLACED;
            const isExp = expanded === (order.orderId || order.order_id);
            return (
              <div key={order.orderId || order.order_id} className={`order-card ${isExp ? 'expanded' : ''}`}>
                <div className="order-card-header" onClick={() => setExpanded(isExp ? null : (order.orderId || order.order_id))}>
                  <div className="order-meta">
                    <span className="order-id">Order #{order.orderId || order.order_id}</span>
                    <span className="order-date">{new Date(order.orderDate || order.order_date).toLocaleDateString('en-IN', { day: 'numeric', month: 'short', year: 'numeric' })}</span>
                  </div>
                  <div style={{ display: 'flex', alignItems: 'center', gap: '16px' }}>
                    <span className="order-status-badge" style={{ color: cfg.color, background: cfg.bg }}>
                      {cfg.icon} {status}
                    </span>
                    <span className="order-total">₹{(order.totalAmount || order.total_amount || 0).toFixed(2)}</span>
                    <span className="expand-icon">{isExp ? '▲' : '▼'}</span>
                  </div>
                </div>
                {isExp && (
                  <div className="order-details">
                    <div className="order-info-grid">
                      <div className="order-info-item">
                        <span>📍 Delivery Address</span>
                        <p>{order.deliveryAddress || order.delivery_address || 'N/A'}</p>
                      </div>
                      <div className="order-info-item">
                        <span>💳 Payment Status</span>
                        <p className={order.paymentStatus === 'PAID' ? 'paid' : 'pending'}>
                          {order.paymentStatus || order.payment_status || 'PENDING'}
                        </p>
                      </div>
                    </div>
                    <div className="order-progress">
                      {['PLACED', 'PROCESSING', 'SHIPPED', 'DELIVERED'].map((s, i) => {
                        const statuses = ['PLACED', 'PROCESSING', 'SHIPPED', 'DELIVERED'];
                        const current = statuses.indexOf(status);
                        return (
                          <div key={s} className={`progress-step ${i <= current ? 'done' : ''}`}>
                            <div className="step-dot">{STATUS_CONFIG[s]?.icon}</div>
                            <span>{s}</span>
                            {i < 3 && <div className={`step-line ${i < current ? 'done' : ''}`}></div>}
                          </div>
                        );
                      })}
                    </div>
                  </div>
                )}
              </div>
            );
          })}
        </div>
      )}
    </div>
  );
};

export default Orders;
